class Solution {
    public int minimumOneBitOperations(int n) {
        if (n == 0) return 0;
        int k = 0;
        while ((1 << k) <= n) k++;
        return (1 << k) - 1 - minimumOneBitOperations((1 << k) - 1 - n);
    }
}
